defmodule MyAppWeb.ChangesetView do
  use MyAppWeb, :view

  def render("error.json", %{changeset: changeset}) do
    # This function uses `Ecto.Changeset.traverse_errors` to format errors
    # in a consistent and readable way for JSON responses.
    %{errors: traverse_errors(changeset)}
  end

  defp traverse_errors(changeset) do
    for {field, {msg, opts}} <- Ecto.Changeset.traverse_errors(changeset), into: %{} do
      if count = opts[:count] do
        {field, String.replace(msg, "%{count}", to_string(count))}
      else
        {field, msg}
      end
    end
  end
end

